<script setup lang="ts">import{computed,ref}from'vue';import{CheckCircle2,MessageCircle,RotateCcw,Sparkles}from'lucide-vue-next';const props=defineProps<{role?:string;prompt?:string;starter?:string;sample?:string}>();const emit=defineEmits<{complete:[]}>();const answer=ref(''),showSample=ref(false);const words=computed(()=>answer.value.trim()?answer.value.trim().split(/\s+/).length:0);function reset(){answer.value='';showSample.value=false}</script>
<template><section class="engine-card conversation-practice"><header><span><MessageCircle/></span><div><small>Native conversation mode</small><h3>Разговор с носителем</h3><p>{{role}}</p></div></header><div class="engine-prompt"><b>Ситуация</b><p>{{prompt}}</p><small>{{starter}}</small></div><textarea v-model="answer" placeholder="Напишите свои реплики на английском…"/><div class="engine-actions"><span>{{words}} слов · цель 40+</span><button class="engine-ghost" @click="reset"><RotateCcw/>Начать заново</button><button :disabled="words<12" @click="showSample=true;emit('complete')"><Sparkles/>Проверить себя</button></div><div v-if="showSample" class="engine-feedback"><CheckCircle2/><div><b>Пример естественного ответа</b><p>{{sample}}</p><small>Сравните порядок слов и выражения. Не копируйте дословно — улучшите свой ответ.</small></div></div></section></template>